 48	type ReduxStateProps = {
 49	  activeTour?: TourInfo;
 50	  duration: DurationInSeconds;
 51	  findValue: string;
 52	  hideValue: string;
 53	  isPageVisible: boolean;
 54	  istioAPIEnabled: boolean;
 55	  kiosk: string;
 56	  layout: MeshLayout;
 57	  mtlsEnabled: boolean;
 58	  refreshInterval: IntervalInMilliseconds;
 59	  showGateways: boolean;
 60	  showLegend: boolean;
 61	  showWaypoints: boolean;
 62	  target: MeshTarget | null;
 63	};
 64	
 65	type ReduxDispatchProps = {
 66	  endTour: () => void;
 67	  onReady: (controller: Controller) => void;
 68	  setDefinition: (meshDefinition: MeshDefinition) => void;
 69	  setLayout: (layout: MeshLayout) => void;
 70	  setTarget: (target: MeshTarget) => void;
 71	  setUpdateTime: (val: TimeInMilliseconds) => void;
 72	  startTour: ({ info, stop }) => void;
 73	  toggleLegend: () => void;
 74	};
 75	
 76	type MeshPageProps = ReduxStateProps &
 77	  ReduxDispatchProps & {
 78	    lastRefreshAt: TimeInMilliseconds; // redux by way of ConnectRefresh
 79	  };
 80	
 81	export type MeshData = {
 82	  elements: DecoratedMeshElements;
 83	  elementsChanged: boolean; // true if current elements differ from previous fetch, can be used as an optimization.
 84	  errorMessage?: string;
 85	  fetchParams: MeshFetchParams;
 86	  isError?: boolean;
 87	  isLoading: boolean;
 88	  loaded: boolean;
 89	  names: string[];
 90	  timestamp: TimeInMilliseconds;
 91	};
 92	
 93	// MeshRefs are passed back from the graph when it is ready, to allow for
 94	// other components, or test code, to manipulate the graph programatically.
 95	export type MeshRefs = {
 96	  getController: () => Controller;
 97	  setSelectedIds: (values: string[]) => void;
 98	};
 99	
100	type MeshPageState = {
101	  isReady: boolean;
102	  meshData: MeshData;
103	  meshRefs?: MeshRefs;
104	};
105	
106	const containerStyle = kialiStyle({
107	  minHeight: '350px',
108	  // TODO: try flexbox to remove this calc
109	  height: 'calc(100vh - 113px)' // View height minus top bar height minus secondary masthead
110	});
111	
112	const kioskContainerStyle = kialiStyle({
113	  minHeight: '350px',
114	  height: 'calc(100vh - 10px)' // View height minus top bar height
115	});
116	
117	const meshChip = kialiStyle({
118	  position: 'absolute',
119	  top: '10px',
120	  left: '10px',
121	  width: 'auto',
122	  zIndex: 2
123	});
124	
125	const meshContainerStyle = kialiStyle({ flex: '1', minWidth: '350px', zIndex: 0, paddingRight: '5px' });
126	const meshWrapperDivStyle = kialiStyle({ position: 'relative', backgroundColor: PFColors.BackgroundColor200 });
127	
128	const meshBackground = kialiStyle({
129	  backgroundColor: PFColors.BackgroundColor100
130	});
131	
132	const MeshErrorBoundaryFallback = (): JSX.Element => {
133	  return (
134	    <div className={meshContainerStyle}>
135	      <EmptyMeshLayout isError={true} isMiniMesh={false} loaded={false} refreshInterval={0} />
136	    </div>
137	  );
138	};
