163	  componentDidMount(): void {
164	    // Let URL override current redux state at mount time. Update URL with unset params.
165	    const urlLayout = HistoryManager.getParam(URLParam.MESH_LAYOUT);
166	
167	    if (urlLayout) {
168	      const validLayout = getValidMeshLayout(urlLayout);
169	      if (validLayout !== this.props.layout) {
170	        this.props.setLayout(validLayout);
171	        HistoryManager.setParam(URLParam.MESH_LAYOUT, validLayout);
172	      }
173	    } else {
174	      HistoryManager.setParam(URLParam.MESH_LAYOUT, this.props.layout);
175	    }
176	
177	    // Connect to mesh data source updates
178	    this.meshDataSource.on('loadStart', this.handleMeshDataSourceStart);
179	    this.meshDataSource.on('fetchError', this.handleMeshDataSourceError);
180	    this.meshDataSource.on('fetchSuccess', this.handleMeshDataSourceSuccess);
181	
182	    // Unless we are waiting for Manual refresh, ensure we initialize the mesh.
183	    if (this.props.refreshInterval !== RefreshIntervalManual && HistoryManager.getRefresh() !== RefreshIntervalManual) {
184	      // Using setTimeout() ensures we wait for the toolbar to render and ensure all redux props are updated
185	      // with URL settings. That in turn ensures the initial fetchParams are correct.
186	      setTimeout(() => this.loadMeshFromBackend(), 0);
187	    }
188	  }
189	
190	  componentDidUpdate(prev: MeshPageProps): void {
191	    const curr = this.props;
192	
193	    // we need to consider URL prop here because redux may not yet reflect any change applied in the Refresh component, and
194	    // the initial update needs to know whether to wait on fetching the mesh data.
195	    const manualRefresh =
196	      curr.refreshInterval === RefreshIntervalManual || HistoryManager.getRefresh() === RefreshIntervalManual;
197	
198	    if (
199	      prev.lastRefreshAt !== curr.lastRefreshAt ||
200	      (!manualRefresh &&
201	        ((prev.refreshInterval !== curr.refreshInterval && curr.refreshInterval !== RefreshIntervalPause) ||
202	          prev.duration !== curr.duration ||
203	          (prev.findValue !== curr.findValue && curr.findValue.includes('label:')) ||
204	          (prev.hideValue !== curr.hideValue && curr.hideValue.includes('label:')) ||
205	          prev.showGateways !== curr.showGateways ||
206	          prev.showWaypoints !== curr.showWaypoints))
207	    ) {
208	      this.loadMeshFromBackend();
209	    }
210	
211	    if (prev.layout !== curr.layout) {
212	      this.errorBoundaryRef.current.cleanError();
213	    }
214	
215	    if (curr.showLegend && this.props.activeTour) {
216	      this.props.endTour();
217	    }
218	  }
219	
220	  componentWillUnmount(): void {
221	    // Disconnect from mesh data source updates
222	    this.meshDataSource.removeListener('loadStart', this.handleMeshDataSourceStart);
223	    this.meshDataSource.removeListener('fetchError', this.handleMeshDataSourceError);
224	    this.meshDataSource.removeListener('fetchSuccess', this.handleMeshDataSourceSuccess);
225	  }
226	
227	  render(): React.ReactNode {
228	    const conStyle = isKioskMode() ? kioskContainerStyle : containerStyle;
229	    const isEmpty = !(this.state.meshData.elements.nodes && Object.keys(this.state.meshData.elements.nodes).length > 0);
230	    const isReady = !(isEmpty || this.state.meshData.isError);
231	    const refreshInterval = HistoryManager.getRefresh() ?? this.props.refreshInterval;
232	
233	    return (
234	      <>
235	        <FlexView className={conStyle} column={true}>
236	          <MeshToolbar
237	            controller={this.state.meshRefs?.getController()}
238	            disabled={this.state.meshData.isLoading}
239	            elementsChanged={this.state.meshData.elementsChanged}
240	            onToggleHelp={this.toggleHelp}
241	          />
242	          <FlexView grow={true} className={`${meshWrapperDivStyle}`}>
243	            <ErrorBoundary
244	              ref={this.errorBoundaryRef}
245	              onError={this.notifyError}
246	              fallBackComponent={<MeshErrorBoundaryFallback />}
247	            >
248	              {this.props.showLegend && <MeshLegend closeLegend={this.props.toggleLegend} />}
249	
250	              {isReady && (
251	                <Chip className={`${meshChip} ${meshBackground}`} isReadOnly={true}>
252	                  {this.displayTimeRange()}
253	                </Chip>
254	              )}
255	
256	              <div id="mesh-container" className={meshContainerStyle}>
257	                <EmptyMeshLayout
258	                  action={this.handleEmptyMeshAction}
259	                  elements={this.state.meshData.elements}
260	                  error={this.state.meshData.errorMessage}
261	                  isError={!!this.state.meshData.isError}
262	                  isLoading={this.state.meshData.isLoading}
263	                  isMiniMesh={false}
264	                  loaded={this.state.meshData.loaded}
265	                  refreshInterval={refreshInterval}
266	                >
267	                  <Mesh {...this.props} isMiniMesh={false} meshData={this.state.meshData} onReady={this.handleReady} />
268	                </EmptyMeshLayout>
269	              </div>
270	            </ErrorBoundary>
271	
272	            {this.props.target && (
273	              <TargetPanel
274	                duration={this.props.duration}
275	                isPageVisible={this.props.isPageVisible}
276	                istioAPIEnabled={this.props.istioAPIEnabled}
277	                meshData={this.state.meshData}
278	                refreshInterval={this.props.refreshInterval}
279	                target={this.props.target}
280	                updateTime={this.state.meshData.timestamp / 1000}
281	              />
282	            )}
283	          </FlexView>
284	        </FlexView>
285	      </>
286	    );
287	  }
288	
289	  private handleReady = (refs: MeshRefs): void => {
290	    this.setState({ isReady: true, meshRefs: refs });
291	  };
292	
293	  private handleEmptyMeshAction = (): void => {
294	    // treat this like a manual refresh, the user is explicitly asking for a mesh-gen
295	    this.loadMeshFromBackend();
296	  };
297	
298	  private handleMeshDataSourceSuccess = (
299	    meshNames: string[],
300	    meshTimestamp: TimeInSeconds,
301	    elements: DecoratedMeshElements,
302	    fetchParams: MeshFetchParams
303	  ): void => {
304	    const prevElements = this.state.meshData.elements;
305	    const elementsChanged = this.elementsChanged(prevElements, elements);
306	    this.setState({
307	      meshData: {
308	        elements: elements,
309	        elementsChanged: elementsChanged,
310	        fetchParams: fetchParams,
311	        isLoading: false,
312	        loaded: true,
313	        names: meshNames,
314	        timestamp: meshTimestamp * 1000
315	      }
316	    });
317	
318	    this.props.setDefinition(this.meshDataSource.meshDefinition);
319	  };
320	
321	  private handleMeshDataSourceError = (errorMessage: string | null, fetchParams: MeshFetchParams): void => {
322	    const prevElements = this.state.meshData.elements;
323	
324	    this.setState({
325	      meshData: {
326	        elements: EMPTY_MESH_DATA,
327	        elementsChanged: this.elementsChanged(prevElements, EMPTY_MESH_DATA),
328	        errorMessage: !!errorMessage ? errorMessage : undefined,
329	        fetchParams: fetchParams,
330	        isError: true,
331	        isLoading: false,
332	        loaded: true,
333	        names: [UNKNOWN],
334	        timestamp: Date.now()
335	      }
336	    });
337	  };
338	
339	  private handleMeshDataSourceStart = (isPreviousDataInvalid: boolean, fetchParams: MeshFetchParams): void => {
340	    this.setState({
341	      meshData: {
342	        elements: isPreviousDataInvalid ? EMPTY_MESH_DATA : this.state.meshData.elements,
343	        elementsChanged: false,
344	        fetchParams: fetchParams,
345	        isLoading: true,
346	        loaded: this.state.meshData.loaded,
347	        names: isPreviousDataInvalid ? [UNKNOWN] : this.state.meshData.names,
348	        timestamp: isPreviousDataInvalid ? Date.now() : this.state.meshData.timestamp
349	      }
350	    });
351	  };
352	
353	  private toggleHelp = (): void => {
354	    if (this.props.showLegend) {
355	      this.props.toggleLegend();
356	    }
357	
358	    if (this.props.activeTour) {
359	      this.props.endTour();
360	    } else {
361	      const firstStop = getNextTourStop(MeshTour, -1, 'forward');
362	      this.props.startTour({ info: MeshTour, stop: firstStop });
363	    }
364	  };
365	
366	  private loadMeshFromBackend = (): void => {
367	    if (!this.meshDataSource.isLoading) {
368	      this.meshDataSource.fetchMeshData({
369	        includeLabels: this.props.findValue.includes('label:') || this.props.hideValue.includes('label:'),
370	        showGateways: this.props.showGateways,
371	        showWaypoints: this.props.showWaypoints
372	      });
373	    }
374	  };
375	
376	  private notifyError = (error: Error, _componentStack: string): void => {
377	    AlertUtils.add(`There was an error when rendering the mesh: ${error.message}, please try a different layout`);
378	  };
379	
380	  // It is common that when updating the mesh that the element topology (nodes, edges) remain the same,
381	  // When the topology remains the same we may be able to optimize
382	  // some behavior.  This returns true if the topology changes, false otherwise.
383	  // 1) Quickly compare the number of nodes and edges, if different return true.
384	  // 2) Compare the ids
385	  private elementsChanged = (prevElements: DecoratedMeshElements, nextElements: DecoratedMeshElements): boolean => {
386	    if (prevElements === nextElements) {
387	      return false;
388	    }
389	
390	    if (
391	      !prevElements ||
392	      !nextElements ||
393	      !prevElements.nodes ||
394	      !prevElements.edges ||
395	      !nextElements.nodes ||
396	      !nextElements.edges ||
397	      prevElements.nodes.length !== nextElements.nodes.length ||
398	      prevElements.edges.length !== nextElements.edges.length
399	    ) {
400	      return true;
401	    }
402	
403	    const sameIds =
404	      this.nodeOrEdgeArrayHasSameIds(nextElements.nodes, prevElements.nodes) &&
405	      this.nodeOrEdgeArrayHasSameIds(nextElements.edges, prevElements.edges);
406	
407	    return !sameIds;
408	  };
409	
410	  private nodeOrEdgeArrayHasSameIds = <T extends DecoratedMeshNodeWrapper | DecoratedMeshEdgeWrapper>(
411	    a: Array<T>,
412	    b: Array<T>
413	  ): boolean => {
414	    const aIds = a.map(e => e.data.id).sort();
415	    return b
416	      .map(e => e.data.id)
417	      .sort()
418	      .every((eId, index) => eId === aIds[index]);
419	  };
420	
421	  private displayTimeRange = (): string => {
422	    const rangeEnd: TimeInMilliseconds = this.state.meshData.timestamp;
423	    const rangeStart: TimeInMilliseconds = rangeEnd - this.props.duration * 1000;
424	
425	    return toRangeString(rangeStart, rangeEnd, { second: '2-digit' }, { second: '2-digit' });
426	  };
427	}
