435	  isPageVisible: state.globalState.isPageVisible,
436	  kiosk: state.globalState.kiosk,
437	  layout: state.mesh.layout,
438	  mtlsEnabled: meshWideMTLSEnabledSelector(state),
439	  refreshInterval: refreshIntervalSelector(state),
440	  showGateways: state.mesh.toolbarState.showGateways,
441	  showLegend: state.mesh.toolbarState.showLegend,
442	  showWaypoints: state.mesh.toolbarState.showWaypoints,
443	  target: state.mesh.target
444	});
445	
446	const mapDispatchToProps = (dispatch: KialiDispatch): ReduxDispatchProps => ({
447	  endTour: bindActionCreators(TourActions.endTour, dispatch),
448	  onReady: (controller: Controller) => dispatch(MeshThunkActions.meshReady(controller)),
449	  setDefinition: bindActionCreators(MeshActions.setDefinition, dispatch),
450	  setLayout: bindActionCreators(MeshActions.setLayout, dispatch),
451	  setTarget: bindActionCreators(MeshActions.setTarget, dispatch),
452	  setUpdateTime: bindActionCreators(MeshActions.setUpdateTime, dispatch),
453	  startTour: bindActionCreators(TourActions.startTour, dispatch),
454	  toggleLegend: bindActionCreators(MeshToolbarActions.toggleLegend, dispatch)
455	});
456	
457	export const MeshPage = connectRefresh(connect(mapStateToProps, mapDispatchToProps)(MeshPageComponent));

